package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private static Method isLineBreakCharMethod;
    private static Method isLineBreakCharacterMethod;

    @BeforeAll
    public static void setUp() throws Exception {
        // Access private static method isLineBreak(Character)
        isLineBreakCharacterMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakCharacterMethod.setAccessible(true);

        // Access private static method isLineBreak(char)
        isLineBreakCharMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        isLineBreakCharMethod.setAccessible(true);
    }

    @Test
    public void testIsLineBreakWithNullCharacter() throws Exception {
        Boolean result = (Boolean) isLineBreakCharacterMethod.invoke(null, (Object) null);
        assertFalse(result);
    }

    @Test
    public void testIsLineBreakWithLineBreakCharacters() throws Exception {
        // Characters that should return true
        char[] lineBreakChars = {'\r', '\n'};
        for (char c : lineBreakChars) {
            // test char version
            Boolean resultChar = (Boolean) isLineBreakCharMethod.invoke(null, c);
            assertTrue(resultChar, "Expected true for char: " + (int) c);

            // test Character version
            Boolean resultCharacter = (Boolean) isLineBreakCharacterMethod.invoke(null, Character.valueOf(c));
            assertTrue(resultCharacter, "Expected true for Character: " + (int) c);
        }
    }

    @Test
    public void testIsLineBreakWithNonLineBreakCharacters() throws Exception {
        // Characters that should return false
        char[] nonLineBreakChars = {'a', ' ', ',', '\t', '1', 'X', 0, 127};
        for (char c : nonLineBreakChars) {
            // test char version
            Boolean resultChar = (Boolean) isLineBreakCharMethod.invoke(null, c);
            assertFalse(resultChar, "Expected false for char: " + (int) c);

            // test Character version
            Boolean resultCharacter = (Boolean) isLineBreakCharacterMethod.invoke(null, Character.valueOf(c));
            assertFalse(resultCharacter, "Expected false for Character: " + (int) c);
        }
    }
}
